#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int W[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &W[i]);
        }
        int minVelocity = W[0];
        for (int i = 1; i < N; i++) {
            if (minVelocity < W[i]) {
                minVelocity = W[i];
            }
        }
        printf("%d\n", minVelocity);
    }
    return 0;
}

