import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] W = new int[N];
            for (int i = 0; i < N; i++) {
                W[i] = sc.nextInt();
            }
            int minVelocity = W[0];
            for (int i = 1; i < N; i++) {
                if (minVelocity < W[i]) {
                    minVelocity = W[i];
                }
            }
            System.out.println(minVelocity);
        }
    }
}

