const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const W = readline().split(' ').map(x => parseInt(x));
    let minVelocity = W[0];
    for (let j = 1; j < N; j++) {
        if (minVelocity < W[j]) {
            minVelocity = W[j];
        }
    }
    console.log(minVelocity);
}
